async function main() {
  const existing = await prisma.bMWPayment.count()
  if (existing > 0) {
    console.log('BMW payments already seeded, skipping (' + existing + ' records)')
    return
  }
  const result = await prisma.bMWPayment.createMany({ data: BMW_DATA })
  console.log('Seeded ' + result.count + ' BMW payment records')
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect())
